import urllib, sys, json
import requests
 
def lambda_handler(event):
    # This is a sample Python script.
    # Write the Python code in this document to process a webhook request sent by Slack 
    # This is an example of what your could copy/paste:
    
    url = event['url']

    try:
        response = urllib.request.urlopen('http://url', context=None)
    except requests.RequestException as e:
        # Not nice to have this, but we catch the exception here so that it 
        # can be handled properly by the caller.
        print(e)
        return {
            "statusCode": 400,
            "body": json.dumps("Bad URL")
        }
    
    return {
        'statusCode': 200,
        'headers': {"Content-Type": "application/json"}, 
        'body': response
    }